import { useState, useEffect } from 'react';
import { Moon, Sun, Menu, X, Download } from 'lucide-react';
import { useApp } from '../context/AppContext';
import t from '../i18n/translations';

export default function Navbar() {
  const { dark, setDark, lang, setLang } = useApp();
  const tr = t[lang];
  const [scrolled, setScrolled] = useState(false);
  const [active,   setActive]   = useState('');
  const [open,     setOpen]     = useState(false);

  const links = [
    { id:'about',      label: tr.about },
    { id:'projects',   label: tr.projectsNav },
    { id:'experience', label: tr.experience },
    { id:'certs',      label: tr.certs },
    { id:'contact',    label: tr.contact },
  ];

  useEffect(() => {
    const fn = () => {
      setScrolled(window.scrollY > 40);
      let cur = '';
      document.querySelectorAll('section[id]').forEach(s => {
        if (window.scrollY >= s.offsetTop - 130) cur = s.id;
      });
      setActive(cur);
    };
    window.addEventListener('scroll', fn, { passive: true });
    return () => window.removeEventListener('scroll', fn);
  }, []);

  const navStyle = scrolled ? {
    background: dark ? 'rgba(15,15,20,0.82)' : 'rgba(253,252,249,0.82)',
    backdropFilter: 'blur(28px) saturate(180%)',
    WebkitBackdropFilter: 'blur(28px) saturate(180%)',
    borderBottom: `1px solid ${dark ? 'rgba(255,255,255,0.07)' : 'rgba(255,255,255,0.85)'}`,
    boxShadow: dark ? '0 4px 24px rgba(0,0,0,0.3)' : '0 4px 24px rgba(26,26,46,0.06)',
  } : {};

  const ink  = dark ? '#f0f0f8' : '#1a1a2e';
  const muted = dark ? 'rgba(255,255,255,0.55)' : '#8a8a9a';
  const lc = id => ({ color: active === id ? '#f0a500' : muted, transition: 'color 0.2s' });

  return (
    <nav className="fixed inset-x-0 top-0 z-50 flex items-center justify-between px-4 sm:px-[5%] py-3 sm:py-4 transition-all duration-300" style={navStyle}>

      {/* Logo — only M is amber */}
      <a href="#hero" className="font-serif-display text-2xl tracking-tight select-none">
        <span style={{ color: ink }}>Ke</span>
        <span style={{ color: '#f0a500' }}>M</span>
        <span style={{ color: ink }}>oO.</span>
      </a>

      <ul className="hidden md:flex gap-7">
        {links.map(l => (
          <li key={l.id}>
            <a href={`#${l.id}`} className="text-sm font-medium hover:text-amber transition-colors" style={lc(l.id)}>
              {l.label}
            </a>
          </li>
        ))}
      </ul>

      <div className="flex items-center gap-2">
        <a href={process.env.PUBLIC_URL + "/assets/kareem-cv.pdf"} download="Kareem_Basem_CV.pdf"
          className="hidden md:inline-flex items-center gap-1.5 px-3 py-1.5 rounded-full text-xs font-semibold transition-all hover:-translate-y-0.5"
          style={{ background: 'rgba(240,165,0,0.10)', border: '1px solid rgba(240,165,0,0.28)', color: '#f0a500' }}>
          <Download size={12} /> CV
        </a>

        <button onClick={() => setLang(lang === 'en' ? 'ar' : 'en')}
          className="px-3 py-1.5 rounded-full text-xs font-semibold border transition-all hover:border-amber hover:text-amber"
          style={{ borderColor: dark ? 'rgba(255,255,255,0.14)' : 'rgba(26,26,46,0.14)', color: muted }}>
          {lang === 'en' ? 'ع' : 'EN'}
        </button>

        <button onClick={() => setDark(!dark)}
          className="w-9 h-9 rounded-full border flex items-center justify-center transition-all hover:border-amber hover:text-amber"
          style={{ borderColor: dark ? 'rgba(255,255,255,0.14)' : 'rgba(26,26,46,0.14)', color: dark ? '#f0a500' : muted, background: dark ? 'rgba(255,255,255,0.04)' : 'transparent' }}>
          {dark ? <Sun size={15}/> : <Moon size={15}/>}
        </button>

        <a href="mailto:karemalwy1@gmail.com"
          className="hidden md:inline-block px-4 py-2 text-sm font-semibold rounded-full transition-all hover:-translate-y-0.5"
          style={{ background: dark ? 'rgba(255,255,255,0.08)' : '#1a1a2e', color: dark ? '#f0f0f8' : '#fdfcf9', border: dark ? '1px solid rgba(255,255,255,0.10)' : 'none' }}
          onMouseEnter={e => { e.currentTarget.style.background = '#f0a500'; e.currentTarget.style.color = '#fff'; e.currentTarget.style.border = 'none'; }}
          onMouseLeave={e => { e.currentTarget.style.background = dark ? 'rgba(255,255,255,0.08)' : '#1a1a2e'; e.currentTarget.style.color = dark ? '#f0f0f8' : '#fdfcf9'; }}>
          {tr.hireMe}
        </a>

        <button className="md:hidden" onClick={() => setOpen(!open)}>
          {open ? <X size={22} style={{ color: ink }}/> : <Menu size={22} style={{ color: ink }}/>}
        </button>
      </div>

      {open && (
        <div className="absolute top-full left-0 right-0 py-5 flex flex-col items-center gap-4 md:hidden"
          style={{ background: dark ? 'rgba(15,15,20,0.96)' : 'rgba(253,252,249,0.96)', backdropFilter: 'blur(20px)', borderBottom: `1px solid ${dark ? 'rgba(255,255,255,0.07)' : 'rgba(26,26,46,0.07)'}` }}>
          {links.map(l => (
            <a key={l.id} href={`#${l.id}`} onClick={() => setOpen(false)} className="text-sm font-medium" style={lc(l.id)}>{l.label}</a>
          ))}
          <a href={process.env.PUBLIC_URL + "/assets/kareem-cv.pdf"} download className="text-sm font-semibold flex items-center gap-1.5" style={{ color: '#f0a500' }}><Download size={13}/> Download CV</a>
        </div>
      )}
    </nav>
  );
}
